AreaConfig = {}
AreaConfig.Areas = {}

function AreaConfig:init(configs)
    for _, area in pairs(configs) do
        local item = {}
        item.id = tonumber(area.id)
        item.groupId = tonumber(area.groupId)
        item.x = tonumber(area.x)
        item.y = tonumber(area.y)
        item.z = tonumber(area.z)
        item.yaw = tonumber(area.yaw)
        if self.Areas[item.groupId] == nil then
            self.Areas[item.groupId] = {}
        end
        table.insert(self.Areas[item.groupId], item)
    end
end

function AreaConfig:getPositionsByGroupId(id)
    local item = self.Areas[tonumber(id)]
    if item ~= nil then
        return item
    end
end

return AreaConfig